/// Optimize fcmp oeq (select (fcmp oge X, 0), X, fneg X), 0 --> fcmp oeq X, 0.
/// This handles the case where fabs is computed via select/fneg rather than
/// using the fabs intrinsic. The comparison to 0 with oeq/ueq works correctly
/// even without nsz because fcmp treats +0 and -0 as equal.
static Instruction *foldFCmpSelectFNegWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
  // Only handle equality comparisons to zero.
  if (!I.isEquality())
    return nullptr;

  const APFloat *C;
  if (!match(I.getOperand(1), m_APFloat(C)) || !C->isZero())
    return nullptr;

  SelectInst *SI = dyn_cast<SelectInst>(I.getOperand(0));
  if (!SI)
    return nullptr;

  Value *TrueVal = SI->getTrueValue();
  Value *FalseVal = SI->getFalseValue();
  Value *Cond = SI->getCondition();

  FCmpInst *FCmp = dyn_cast<FCmpInst>(Cond);
  if (!FCmp)
    return nullptr;

  Value *X = nullptr;
  Value *NegX = nullptr;

  // Check if select arms are X and fneg(X).
  if (match(TrueVal, m_Value(X)) && match(FalseVal, m_FNeg(m_Specific(X)))) {
    NegX = FalseVal;
  } else if (match(FalseVal, m_Value(X)) && match(TrueVal, m_FNeg(m_Specific(X)))) {
    NegX = TrueVal;
    std::swap(TrueVal, FalseVal);
  } else {
    return nullptr;
  }

  // The condition must be comparing X to zero.
  if (!FCmp->isOrdered())
    return nullptr;

  Value *CmpLHS = FCmp->getOperand(0);
  Value *CmpRHS = FCmp->getOperand(1);
  FCmpInst::Predicate Pred = FCmp->getPredicate();

  // Normalize so the constant is on the RHS.
  if (match(CmpLHS, m_AnyZeroFP())) {
    std::swap(CmpLHS, CmpRHS);
    Pred = FCmpInst::getSwappedPredicate(Pred);
  }

  // Check if comparing X to zero.
  if (!match(CmpRHS, m_AnyZeroFP()) || !match(CmpLHS, m_Specific(X)))
    return nullptr;

  // Now check if the select correctly implements fabs based on the predicate.
  // fabs(X) = (X >= 0) ? X : -X  (or equivalently (X > 0) ? X : -X for non-zero X)
  // fabs(X) = (X < 0) ? -X : X
  // fabs(X) = (X <= 0) ? -X : X
  bool SelectImplementsFAbs = false;

  if (TrueVal == X && NegX == FalseVal) {
    // (cond) ? X : -X
    // For fabs: cond should be (X >= 0) or (X > 0)
    SelectImplementsFAbs = (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_OGT ||
                           Pred == FCmpInst::FCMP_UGE || Pred == FCmpInst::FCMP_UGT);
  } else if (TrueVal == NegX && FalseVal == X) {
    // (cond) ? -X : X
    // For fabs: cond should be (X < 0) or (X <= 0)
    SelectImplementsFAbs = (Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_OLE ||
                           Pred == FCmpInst::FCMP_ULT || Pred == FCmpInst::FCMP_ULE);
  }

  if (!SelectImplementsFAbs)
    return nullptr;

  // Transform: fcmp oeq fabs(X), 0 --> fcmp oeq X, 0
  I.setOperand(0, X);
  return &I;
}

